                        self.mem[sym::tempblocky] = self.mem[sym::moblevel];
                        self.SHAKEM1();
                        self.set_x(self.mem[sym::moblevel]);
                        self.mem[sym::moby] = self.mem[(sym::BlockAy + 1 + self.reg.x as usize) & 0xffff];
                        self.set_a(0xfe);
                        self.mem[sym::mobvel] = self.reg.a;
                        self.makerubble();
                        return;
